def validate_blob_path(blob_path: str) -> bool:
    if not blob_path:
        return False
    
    if '..' in blob_path:
        return False
    
    if blob_path.startswith('/') or blob_path.startswith('\\'):
        return False
    
    dangerous_patterns = ['../', '..\\', '%2e%2e', '%252e']
    blob_path_lower = blob_path.lower()
